{
  "ad_title": "E-Commerce Platform Architecture Description v1.0",
  "system": {
    "name": "E-Commerce Platform",
    "description": "Web-based retail platform handling product catalog, orders, payments, and fulfillment",
    "environment": ["public internet", "third-party payment processors", "logistics APIs", "cloud infrastructure"]
  },
  "stakeholders": [
    { "class": "End Users",      "concerns": ["response time < 2s", "data privacy", "product availability"] },
    { "class": "Developers",     "concerns": ["modularity", "test coverage", "CI/CD clarity"] },
    { "class": "Operators",      "concerns": ["deployment frequency", "observability", "incident response"] },
    { "class": "Security Team",  "concerns": ["PCI-DSS compliance", "authentication strength", "data encryption"] },
    { "class": "Business Owners","concerns": ["revenue uptime", "feature delivery pace", "cost per transaction"] }
  ],
  "viewpoints": [
    {
      "name": "Logical Viewpoint",
      "concerns_addressed": ["modularity", "domain decomposition"],
      "model_kinds": ["UML Component Diagram", "UML Package Diagram"],
      "stakeholders_served": ["Developers"]
    },
    {
      "name": "Deployment Viewpoint",
      "concerns_addressed": ["infrastructure layout", "scalability", "cost per transaction"],
      "model_kinds": ["Cloud Architecture Diagram", "Network Topology Diagram"],
      "stakeholders_served": ["Operators", "Business Owners"]
    },
    {
      "name": "Security Viewpoint",
      "concerns_addressed": ["PCI-DSS compliance", "data encryption", "authentication strength"],
      "model_kinds": ["Threat Model (STRIDE)", "Data Flow Diagram", "Access Control Matrix"],
      "stakeholders_served": ["Security Team"]
    },
    {
      "name": "Behavior Viewpoint",
      "concerns_addressed": ["response time", "data consistency", "order processing flow"],
      "model_kinds": ["UML Sequence Diagram", "State Machine Diagram"],
      "stakeholders_served": ["Developers", "End Users"]
    }
  ],
  "architecture_decisions": [
    {
      "id": "ADR-001",
      "title": "Use microservices over modular monolith",
      "context": "Team will grow to eight squads over two years; deployment independence is a priority concern",
      "decision": "Adopt microservices with one service per bounded context",
      "alternatives_considered": ["Modular monolith", "Serverless functions"],
      "rationale": "Independent deployability outweighs the operational overhead at projected team size",
      "consequences": ["Distributed tracing required", "Service discovery needed", "Data consistency is harder"]
    }
  ]
}
